        private void ProcessChange(PropertyChangedEvent evt, CallbackContext ctx)
        {
            if (ignoreChanges || evt.target != ctx.element || evt.property != ctx.bindingId)
                return;
            switch (stylePropertyId)
            {
                case StylePropertyId.All:
                case StylePropertyId.BackgroundPosition:
                case StylePropertyId.BorderColor:
                case StylePropertyId.BorderRadius:
                case StylePropertyId.BorderWidth:
                case StylePropertyId.Flex:
                case StylePropertyId.Margin:
                case StylePropertyId.Padding:
                case StylePropertyId.Transition:
                case StylePropertyId.UnityBackgroundScaleMode:
                case StylePropertyId.UnityTextOutline:
                    throw new ArgumentOutOfRangeException();
                default:
                    break;
            }

            using var _ = s_VisitorPool.Get(out var visitor);
            visitor.binding = ctx.binding;
            visitor.authoringContext = ctx.authoringContext;
            visitor.bindingId = ctx.bindingId;
            visitor.element = ctx.element;
            var element = ctx.element;
            PropertyContainer.Accept(visitor, ref element, evt.property);
        }

